Code:
public int makeChocolate(int small, int big, int goal) {
    int bigNeeded = goal / 5;
    int remaining = goal % 5;

    if (bigNeeded <= big) {
        if (remaining <= small) {
            return remaining;
        } else {
            return -1;
        }
    } else {
        int tempGoal = goal - (big * 5);
        bigNeeded = 0;

        if (tempGoal <= small) {
            return tempGoal;
        } else {
            return -1;
        }
    }
}

